const root = items?.[0]?.json;

// Normalize
const obj = Array.isArray(root) ? root[0] : root;

// Fallback
if (!obj || !Array.isArray(obj.messages)) {
  return [{ json: { Message: "" } }];
}

// Sort and combine
const combined = obj.messages
  .slice()
  .sort((a, b) => (a?.created_at || 0) - (b?.created_at || 0))
  .map(m => {
    const sender = m?.sender?.full_name || "Unknown";
    const body = m?.body || "";
    const time = new Date(m?.created_at || 0).toISOString();
    return `${sender} (${time}): ${body}`;
  })
  .join("\n\n");

// Return single flat object
return [
  {
    json: {
      Message: combined
    }
  }
];

// Get timestamps
const inputTimestamp = new Date($input.first().json.body.timestamp); // e.g., 2025-10-27T07:23:57.075Z
const now = new Date($now); // e.g., 2025-11-02T00:50:36.666+07:00

// Calculate time difference in milliseconds
const diffMs = now - inputTimestamp;

// Convert to hours
const diffHours = diffMs / (1000 * 60 * 60);

// Check if within last 48 hours
const result = diffHours <= 48 && diffHours >= 0 ? "Yes" : "No";

return [{ result }];

