// MCO: Seed all historical thread messages EXCEPT the current trigger message.
// The current message is handled exclusively by MCO: Write Inbound — no overlap.
const wb = $('Webhook').first().json.body;
const s = wb.event.sender;
const currentMsgUrn = wb.event.message_urn;
const leadEmail = 'urn_' + s.public_identifier + '@linkedin.placeholder';
const profileUrl = 'https://www.linkedin.com/in/' + s.public_identifier;
const leadName = s.first_name + ' ' + s.last_name;
const leadId = String(s.id);
const raw = $('Thread').first().json;
const msgs = (Array.isArray(raw) ? raw[0] : raw)?.messages || [];
const historical = msgs
  .filter(m => m.urn !== currentMsgUrn)
  .sort((a,b) => (a.created_at||0) - (b.created_at||0));
if (historical.length === 0) return [];
return historical.map(m => {
  const sid = String(m.sender?.id || m.sender || '');
  const dir = sid === leadId ? 'inbound' : 'outbound';
  const eid = m.urn || (wb.event.conversation_urn + '_' + (m.created_at || 0));
  return { json: {
    event_id: eid,
    lead_email: leadEmail,
    timestamp: new Date(m.created_at || Date.now()).toISOString(),
    channel: 'linkedin',
    direction: dir,
    content: m.body || '',
    content_type: 'message',
    sender_name: dir === 'outbound' ? 'Nextus AI' : leadName,
    full_name: leadName,
    linkedin_profile_url: profileUrl
  }};
});

const WRITE_URL = 'https://n8n-1404.n8n.whiteserverdns.com/webhook/mco-write-event';
const SUPA_URL  = 'https://hkqssbomrcbtfbdowtgj.supabase.co';
const SUPA_KEY  = 'REDACTED_SUPABASE_SERVICE_KEY';

const ev = $('Webhook').first().json.body.event;
const s  = ev.sender;
const leadEmail   = 'urn_' + s.public_identifier + '@linkedin.placeholder';
const senderName  = (s.first_name || '') + ' ' + (s.last_name || '');
const linkedinUrl = 'https://www.linkedin.com/in/' + s.public_identifier;

// Check if this lead already exists in Supabase
const checkResp = await fetch(
  SUPA_URL + '/rest/v1/leads?lead_email=eq.' + encodeURIComponent(leadEmail) + '&select=lead_email&limit=1',
  { headers: { apikey: SUPA_KEY, Authorization: 'Bearer ' + SUPA_KEY } }
);
const rows = await checkResp.json();

if (!Array.isArray(rows) || rows.length === 0) {
  // Not in Supabase — first-time lead, do nothing here
  return [{ json: { mco_wrote: false, reason: 'not_in_supabase' } }];
}

// Returning lead — write current inbound + outbound
let outboundContent = '';
try { outboundContent = ($('AI Agent1').first().json.output || '').trim(); } catch(e) {}

await fetch(WRITE_URL, {
  method: 'POST',
  headers: { 'Content-Type': 'application/json' },
  body: JSON.stringify({
    event_id:             ev.message_urn,
    lead_email:           leadEmail,
    timestamp:            ev.timestamp || new Date().toISOString(),
    channel:              'linkedin',
    direction:            'inbound',
    content:              ev.body,
    content_type:         'message',
    sender_name:          senderName,
    full_name:            senderName,
    linkedin_profile_url: linkedinUrl,
    intent:               'unknown'
  })
});

if (outboundContent) {
  await fetch(WRITE_URL, {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      event_id:     ev.message_urn + '_out',
      lead_email:   leadEmail,
      timestamp:    new Date().toISOString(),
      channel:      'linkedin',
      direction:    'outbound',
      content:      outboundContent,
      content_type: 'message',
      sender_name:  'Anik Hanik',
      intent:       'no_action'
    })
  });
}

return [{ json: { mco_wrote: true, lead_email: leadEmail } }];

